const body = $input.first().json.body || $input.first().json;
const rawMessage = body.domain || body.message || body.dominio || '';
const match = String(rawMessage).match(/([a-z0-9-]+\.)+[a-z]{2,}/i);
const dominio = match
  ? match[0].toLowerCase().replace(/^https?:\/\//, '').replace(/^www\./, '').replace(/\/.*$/, '')
  : String(rawMessage).trim();

if (!dominio) {
  throw new Error("Não foi possível identificar um domínio na mensagem recebida.");
}

return [{ json: { dominio, url_base: `https://${dominio}` } }];

const domainData = $('Extrair Domínio').item.json;
const siteHtml = ($('Pesquisar Site do Prospect').item.json.data) || '';
const searxData = $json;
const searxResults = (searxData.results || []).slice(0, 5);

const textoLimpo = String(siteHtml)
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 3000);

const resumoBusca = searxResults
  .map((r, i) => `${i + 1}. ${r.title} — ${r.content || ''}`)
  .join('\n');

const perfil_pesquisa = [
  `Domínio: ${domainData.dominio}`,
  `Conteúdo do site institucional (trecho): ${textoLimpo || 'não foi possível acessar o site.'}`,
  `Resultados de busca externa (SearXNG):\n${resumoBusca || 'nenhum resultado relevante encontrado.'}`,
].join('\n\n');

return [{ json: { dominio: domainData.dominio, perfil_pesquisa } }];

const perfil = $('Compilar Perfil de Pesquisa').item.json;
const qdrantResp = $json;
const points = (qdrantResp.result && qdrantResp.result.points) || [];

const casesTexto = points.map((p, i) => {
  const c = p.payload;
  return `Case ${i + 1} (similaridade ${p.score.toFixed(2)}): "${c.titulo}"\n`
    + `Classificação correta: ${c.classificacao_correta}\n`
    + `Sinais de diagnóstico: ${(c.sinais_diagnostico || []).join(' | ')}\n`
    + `Abordagem recomendada: ${c.abordagem_recomendada}`;
}).join('\n\n');

const prompt = `Você é um analista de pré-vendas de uma consultoria especializada em IA. Sua tarefa é qualificar um prospect a partir da pesquisa abaixo, decidindo se a demanda dele é GenAI real, RPA, BI ou Automação clássica.

PESQUISA SOBRE O PROSPECT:
${perfil.perfil_pesquisa}

CASES SIMILARES DA CONSULTORIA (use como referência de diagnóstico, não copie literalmente):
${casesTexto || 'Nenhum case similar encontrado.'}

Responda SOMENTE em JSON válido seguindo exatamente o schema fornecido. Seja honesto: se a pesquisa não trouxe sinal suficiente, use "confianca": "Baixa" e diga isso na justificativa.`;

const cases_relevantes = points.map((p) => ({
  titulo: p.payload.titulo,
  classificacao: p.payload.classificacao_correta,
  similaridade: Math.round(p.score * 100) / 100,
  licao_aplicavel: p.payload.resultado_licao,
}));

return [{ json: { dominio: perfil.dominio, prompt, cases_relevantes } }];

const montado = $('Montar Prompt').item.json;
const ollamaResp = $json;

let parsed;
try {
  parsed = JSON.parse(ollamaResp.response);
} catch (e) {
  parsed = null;
}

if (!parsed) {
  return [{ json: {
    markdown: `⚠️ Não consegui interpretar a resposta do modelo para o domínio **${montado.dominio}**. Tente novamente.\n\nResposta bruta:\n${ollamaResp.response || ''}`
  } }];
}

const disclaimer = 'Esta é uma recomendação gerada por IA para apoiar o direcionamento comercial. A decisão final sobre estratégia e discovery é do vendedor.';

const casesTexto = (montado.cases_relevantes || []).map((c, i) =>
  `${i + 1}. **${c.titulo}** _(${c.classificacao}, similaridade ${c.similaridade})_\n   ${c.licao_aplicavel}`
).join('\n');

const markdown = `## Qualificação — ${parsed.dominio || montado.dominio}

**Perfil da empresa:** ${parsed.perfil_empresa.resumo}
- Setor: ${parsed.perfil_empresa.setor}
- Porte estimado: ${parsed.perfil_empresa.porte_estimado}
- Sinais de maturidade digital: ${(parsed.perfil_empresa.sinais_maturidade_digital || []).join('; ')}

**Classificação:** ${parsed.classificacao.tipo} _(confiança: ${parsed.classificacao.confianca})_
${parsed.classificacao.justificativa}

**Maturidade em IA do prospect:** ${parsed.maturidade_ia_prospect.nivel}
${parsed.maturidade_ia_prospect.justificativa}

**Direcionamento sugerido:** ${parsed.direcionamento_estrategia.recomendacao}
${parsed.direcionamento_estrategia.justificativa}

**Perguntas de discovery sugeridas:**
${parsed.perguntas_discovery.map((q) => `- ${q}`).join('\n')}

**Cases relevantes da consultoria:**
${casesTexto || '_nenhum case suficientemente similar encontrado._'}

---
_${disclaimer}_`;

return [{ json: { markdown } }];
